const input = $input.first()?.json ?? {};
const source = input.query ?? input;
const intValue = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number.parseInt(String(value), 10);
  return Number.isInteger(parsed) ? parsed : null;
};
return [{
  json: {
    batch_id: intValue(source.batch_id ?? source.batchId),
    member: source.member ?? '',
    venue_id: source.venue_id ?? source.venueId ?? '',
    btn: source.btn ?? source.british_tennis_number ?? source.britishTennisNumber ?? '',
    payer: source.payer ?? '',
    email_address: source.email_address ?? source.email ?? '',
    address_1: source.address_1 ?? '',
    address_2: source.address_2 ?? '',
    address_3: source.address_3 ?? '',
    town: source.town ?? '',
    postcode: source.postcode ?? '',
    regular_tags: intValue(source.regular_tags ?? source.regularTags) ?? 0,
    parent_tags: intValue(source.parent_tags ?? source.parentTags) ?? 0,
    key_tags: intValue(source.key_tags ?? source.keyTags) ?? 0,
    notes: source.notes ?? '',
    created_by: source.created_by ?? source.request_source ?? 'manual_workflow',
  },
}];

